scwin.f_getParametrSetting = async function (gubun) {
  switch (gubun) {
    case "0":
      break;
    case "1":
      // house Search에서 옴
      cnd_ed_mhmblno.setValue(scwin.v_mblno);
      scwin.hd_kcomcd = scwin.v_kcomcd;
      ed_mhvslcd.setValue(scwin.v_vslcd);
      txt_mhvsl.setValue(scwin.v_vsl);
      ed_mhvyg.setValue(scwin.v_vyg);

      // ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
      // ds_retrieve.set("mhmblno", scwin.cnd_ed_mhmblno.getValue());
      // ds_retrieve.set("mhno", "");
      // ds_retrieve.set("mhio", "O");
      // ds_retrieve.set("mhvslcd", scwin.v_vslcd);
      // ds_retrieve.set("mhvsl", scwin.v_vsl);
      // ds_retrieve.set("mhvyg", scwin.v_vyg);

      /* ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
      ds_retrieve.set("mhmblno", cnd_ed_mhmblno.getValue());
      ds_retrieve.set("mhno", "");
      ds_retrieve.set("mhio", scwin.hd_mhio);
      ds_retrieve.set("mhvslcd", scwin.v_vslcd);
      ds_retrieve.set("mhvsl", scwin.v_vsl);
      ds_retrieve.set("mhvyg", scwin.v_vyg); */

      ds_retrieve.setCellData(0, "kcomcd", scwin.hd_kcomcd);
      ds_retrieve.setCellData(0, "mhmblno", cnd_ed_mhmblno.getValue());
      ds_retrieve.setCellData(0, "mhno", "");
      ds_retrieve.setCellData(0, "mhio", scwin.hd_mhio);
      ds_retrieve.setCellData(0, "mhvslcd", scwin.v_vslcd);
      ds_retrieve.setCellData(0, "mhvsl", scwin.v_vsl);
      ds_retrieve.setCellData(0, "mhvyg", scwin.v_vyg);
      var rtn = await $c.sbm.execute($p, sbm_retrieveDraftMhno);
      if (rtn.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        if (ds_mmhno.getRowCount() == 0 || $c.util.isEmpty($p, ds_mmhno.getCellData(0, "mhno"))) {
          await scwin.f_RetrieveDraftBl();
          await scwin.f_Set("CREATE");
          $c.gus.cfEnableObjects($p, [ed_mhvslcd, txt_mhvsl, ed_mhvyg]); // 조회조건. 
        } else if (ds_mmhno.getRowCount() > 0 && !$c.util.isEmpty($p, ds_mmhno.getCellData(0, "mhno"))) {
          await scwin.f_CndMhmblnoLoading();
          cnd_lc_mhno.setSelectedIndex(0);
          scwin.f_Retrieve();
        }
      }
      break;
    case "3":
      // house Search에서 옴
      scwin.mhnoFlag = "1";
      cnd_ed_hhblno.setValue(scwin.v_blno);
      scwin.cnd_ed_hhblno_onblur();
      scwin.hd_kcomcd = scwin.v_kcomcd;
      if (ds_hmhno.getRowCount() == 0) {
        ds_hmhno.insertRow(0);
      }
      // ds_hmhno.setCellData(0, "code", scwin.v_mhno);
      // ds_hmhno.setCellData(0, "name", scwin.v_mhno);
      ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
      ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
      cnd_lc_mhno.setSelectedIndex(0);
      $p.setTimeout(scwin.f_Retrieve, {
        delay: 200
      });
      break;
    case "5":
      // House B/L에서 생성(create)
      await scwin.f_Create();
      ed_mhvslcd.setValue(scwin.v_vslcd);
      txt_mhvsl.setValue(scwin.v_vsl);
      ed_mhvyg.setValue(scwin.v_vyg);
      await scwin.f_RetrieveVessel();

      //tobe위치변경 : 시점 문제로 인해 f_RetrieveVessel 함수 서비스 후처리 안으로 위치 변경
      // ed_mhscd.setValue("114403");
      // txt_mhsnm.setValue("DONGWON LOEX CO., LTD.");
      // scwin.f_MasterSum();

      break;
  }
};

