//-------------------------------------------------------------------------
// Send EDI Before
//-------------------------------------------------------------------------
scwin.f_SendEDI_Before = async function (flag) {
  await scwin.f_seaCargoManifestCnt();
  var seaCargoManifestYn = "";
  if (ds_SeaCargoManifestCount.getRowCount() > 0) {
    seaCargoManifestYn = ds_SeaCargoManifestCount.getCellData(0, "code");
  }
  var status = ""; // 0;

  if ("0" != seaCargoManifestYn) {
    status = "U"; // 3 : update
    await scwin.f_seaCargoManifestSet("U");
  } else {
    status = "C"; // 1 : insert
    await scwin.f_seaCargoManifestSet("C");
  }
  for (var i = 0; i < ds_House.getRowCount(); i++) {
    ds_House.modifyRowStatus(i, "C"); // insert
    ds_House.setCellData(i, "edigubun", "I");
  }
  await $c.sbm.execute($p, sbm_blCheck);
  for (var j = 0; j < ds_House.getRowCount(); j++) {
    ds_House.modifyRowStatus(j, status);
    ds_House.setCellData(j, "edigubun", "S"); //update 전송문제 해결
  }
  if (ds_BLcheck.getRowCount() > 0 && ds_BLcheck.getCellData(0, "flag") == -1) {
    var errMsg = "MBL NO (" + ds_BLcheck.getCellData(0, "mblno") + ") / HBL NO (" + ds_BLcheck.getCellData(0, "hblno") + ") / " + ds_BLcheck.getCellData(0, "descnm");
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_055, [errMsg]);
    return false;
  } else {
    if (ds_ocMblhList.getCellData(0, "mhmblno") == "" && ds_ocMblhList.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, ["MBL NO"]);
      return false;
    }
    if (ds_ocMblhList.getCellData(0, "mhmrnno") == "" && ds_ocMblhList.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, ["MRN No"]);
      return false;
    }
    if (ds_SeaCargoManifest.getCellData(0, "ediliner") == "" && ds_SeaCargoManifest.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, ["Edi Liner"]);
      return false;
    }
    if (ds_SeaCargoManifest.getCellData(0, "custom") == "" && ds_SeaCargoManifest.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, Array("관할세관"));
      return false;
    }
    if (ds_SeaCargoManifest.getCellData(0, "depart") == "" && ds_SeaCargoManifest.getRowCount() > 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, Array("세관과"));
      return false;
    }
    if (flag == 0) {
      var rtn = await $c.sbm.execute($p, sbm_saveSeaCargoManifest);
      if (rtn.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        scwin.f_SendEDI();
      }
    }
    if (flag == 1) {
      await $c.sbm.execute($p, sbm_saveSeaCargoManifest_print);
    }
  }
  return true;
};

//-------------------------------------------------------------------------
// Send EDI
//-------------------------------------------------------------------------
scwin.f_SendEDI = async function () {
  ds_SendEDI.removeAll();
  ds_SendEDI.insertRow(0);
  ds_SendEDI.setCellData(0, "kcomcd", scwin.hd_kcomcd);
  ds_SendEDI.setCellData(0, "mrnno", ds_SeaCargoManifest.getCellData(0, "mrnno"));
  ds_SendEDI.setCellData(0, "ediliner", ds_SeaCargoManifest.getCellData(0, "ediliner"));
  ds_SendEDI.setCellData(0, "mhno", ds_SeaCargoManifest.getCellData(0, "mhno"));
  ds_SendEDI.setCellData(0, "gubun", "SeaCargoManifest");
  var result = await $c.sbm.execute($p, sbm_sendedi);
  if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_018); // 성공적으로 전송 하였습니다

    scwin.f_Retrieve();
    scwin.f_Set("SAVE");
    scwin.f_ContentsDisplay(); // 조건 display
  }
};

