scwin.f_RetrieveVessel = async function () {
  if (scwin.statusFlag != "C") {
    return;
  }
  if ($c.util.isEmpty($p, ed_mhvslcd.getValue()) && $c.util.isEmpty($p, txt_mhvsl.getValue()) && $c.util.isEmpty($p, ed_mhvyg.getValue())) {
    ds_ocHblhList.removeAll();
    ds_ocContList.removeAll();
    ds_ocMblhList.removeAll();
    return;
  }
  ds_vessel.setCellData(ds_vessel.getRowPosition() || 0, "kcomcd", scwin.hd_kcomcd);
  ds_vessel.setCellData(ds_vessel.getRowPosition() || 0, "hhblno", scwin.hd_mhio);
  ds_vessel.setCellData(ds_vessel.getRowPosition() || 0, "mhio", scwin.hd_mhio);
  ds_vessel.setCellData(ds_vessel.getRowPosition() || 0, "inpid", scwin.userId);
  // binding으로 함.
  // ds_vessel.setCellData(ds_vessel.getRowPosition()||0, "hhvslcd", ed_mhvslcd.getValue());
  // ds_vessel.setCellData(ds_vessel.getRowPosition()||0, "hhvsl", txt_mhvsl.getValue());
  // ds_vessel.setCellData(ds_vessel.getRowPosition()||0, "hhvyg", ed_mhvyg.getValue());

  var rtn = await $c.sbm.execute($p, sbm_retrieveHouse);
  if (rtn.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    if (ds_ocHblhList.getRowCount() == 0 && ds_vessel.getRowCount() != 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
    } else {
      setTimeout(() => {
        gr_ocHblhList.setFocusedCell(0, 0);
        if (scwin.v_linkcheck == "5") {
          //ed_mhscd.setValue("114403"); 
          ed_mhscd.setValue("109856"); // tobe변경 :  김진성책임님(운영결함 O-0063) 요청으로 해당 코드로 변경
          txt_mhsnm.setValue("DONGWON LOEX CO., LTD.");
          scwin.f_MasterSum();
        }
      }, 50);
    }
    txt_totalOcHblhList.setValue(ds_ocHblhList.getRowCount());
  }
  ed_mhetd.focus(); //event처리위해.
  ed_mhvslcd.focus();
};

