//-------------------------------------------------------------------------
//Master 금액 계산
// 왼쪽 그리드의 선택된 금액들의 합을 실시간으로 오른쪽의 MASTER B/L HEADER에 보여준다.
//------------------------------------------------------------------------- 	
// WebSquare 버전
scwin.f_MasterSum = function () {
  var hhpkg = 0;
  var hhgwgt = 0;
  var hhmsr = 0;
  var hhmsrAll = 0;
  var hhmsrRate = 0;
  var hhmsrRateSum = 0;
  var hhmsrRateAdj = 0;
  ed_mhpkg.setValue("");
  ed_mhwgt.setValue("");
  ed_mhmsr.setValue("");
  var checkRowIdx = gr_ocHblhList.getCheckedIndex("chk");
  for (var i = 0; i < checkRowIdx.length; i++) {
    hhpkg = ds_ocHblhList.getCellData(checkRowIdx[i], "hhpkg") || 0;
    hhgwgt = ds_ocHblhList.getCellData(checkRowIdx[i], "hhgwgt") || 0;
    hhmsr = ds_ocHblhList.getCellData(checkRowIdx[i], "hhmsr") || 0;
    ed_mhpkg.setValue(Number(ed_mhpkg.getValue()) + hhpkg);
    ed_mhwgt.setValue(Number(ed_mhwgt.getValue()) + hhgwgt);
    ed_mhmsr.setValue(Number(ed_mhmsr.getValue()) + hhmsr);
  }
  ed_fhhgwgt.setValue(ed_mhwgt.getValue());
  ed_fhhmsr.setValue(ed_mhmsr.getValue());
  hhmsrAll = Number(ed_mhmsr.getValue()) || 0;
  for (var i = 0; i < ds_ocHblhList.getRowCount(); i++) {
    var vChkYn = ds_ocHblhList.getCellData(i, "chk");
    if (vChkYn == "T") {
      hhmsr = Number(ds_ocHblhList.getCellData(i, "hhmsr"));
      hhmsrRate = Math.round(hhmsr / hhmsrAll * 100);

      //tobe추가.
      if (Number.isNaN(hhmsrRate) || hhmsrRate == Infinity) {
        hhmsrRate = "-1.#I";
        gr_ocHblhList.setDataType("hhmsrrate", "text");
      } else {
        gr_ocHblhList.setDataType("hhmsrrate", "number");
      }
      ds_ocHblhList.setCellData(i, "hhmsrrate", hhmsrRate);
      hhmsrRateSum = hhmsrRateSum + Number(hhmsrRate);
    } else {
      ds_ocHblhList.setCellData(i, "hhmsrrate", 0);
    }
    if (scwin.statusFlag == "C") {
      ds_ocHblhList.setCellData(i, "hhmsrrate", "");
    }
  }
  hhmsrRateAdj = (100 - hhmsrRateSum).toFixed(2);
  for (var i = checkRowIdx.length - 1; i >= 0; i--) {
    hhmsrRate = ds_ocHblhList.getCellData(checkRowIdx[i], "hhmsrrate");
    if (Number(hhmsrRate) > 0 && Number(hhmsrRate) + Number(hhmsrRateAdj) > 0) {
      ds_ocHblhList.setCellData(checkRowIdx[i], "hhmsrrate", Number(hhmsrRate) + Number(hhmsrRateAdj));
      break;
    }
  }
};

