scwin.f_FdeleteRow = async function () {
  // Selling
  var row = ds_selling.getRowPosition() || 0;
  var col = gr_selling.getFocusedColumnIndex();
  var certiNo = ds_selling.getCellData(row, "certino");
  if ($c.util.isEmpty($p, certiNo)) {
    if (ds_selling.getRowStatus(row) == "C") {
      ds_selling.removeRow(row);
    } else {
      ds_selling.deleteRow(row);
      gr_selling.setFocusedCell(row, col);
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
  }
};
//---------------------------------------------------------
