//---------------------------------------------------------
scwin.f_FcancelRow = function () {
  // Selling
  if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(0, "tabIndex") == "0") {
    ds_selling.removeAll();
  } else {
    var createRow = ds_selling.getRowIndexByStatus("C");
    if (createRow.length > 0) {
      ds_selling.removeRows(createRow);
    }
    ds_selling.undoAll();
  }
};

