scwin.f_sellingUnitLoading = async function () {
  function _getCntTypeOrZero(typeComp, cntComp) {
    var t = (typeComp.getValue() || "").toString().trim();
    var c = (cntComp.getValue() || "").toString().trim(); // 숫자라도 문자열로 들어오는 경우 많음
    if (t !== "" && c !== "" && c !== "0") return t;
    return "0";
  }
  var cnt1 = _getCntTypeOrZero(ed_fhhcnt1type, ed_fhhcnt1);
  var cnt2 = _getCntTypeOrZero(ed_fhhcnt2type, ed_fhhcnt2);
  var cnt3 = _getCntTypeOrZero(ed_fhhcnt3type, ed_fhhcnt3);
  var cnt4 = _getCntTypeOrZero(ed_fhhcnt4type, ed_fhhcnt4);

  // "/cm.zz.RetrieveComboCMD.do?sysCd=SeaImportHouseEBC&queryId=retriveUnitList&param1=" + cnt1 + "&param2=" + cnt2 + "&param3=" + cnt3 + "&param4=" + cnt4; 
  scwin._comboTarget = "UNIT_LIST";
  await scwin.f_commCode("SeaImportHouseEBC", "retriveUnitList", cnt1, cnt2, cnt3, cnt4);
};

//-------------------------------------------------------------------------
// tariff버튼 누르면 grid에 package ,rate계산 (Selling)
//------------------------------------------------------------------------- 
scwin.f_packageRateSellingLoading = function (row, colid) {
  // 기준값
  var fhhgwgt = Number(ed_fhhgwgt.getValue() || 0); // g
  var fhhmsr = Number(ed_fhhmsr.getValue() || 0); // cbm(가정)

  var v_wgt = fhhgwgt / 1000; // ton
  var v_msr = fhhmsr;
  var v_wgtR = Math.ceil(v_wgt);
  var v_msrR = Math.ceil(v_msr);
  var fareEngCd = ds_selling.getCellData(row, "fareEngCd");
  var fareUnit = ds_selling.getCellData(row, "fareUnit");
  var wgt = fareEngCd == "WFG" ? v_wgtR : v_wgt;
  var msr = fareEngCd == "WFG" ? v_msrR : v_msr;

  // chgWt 계산
  var chgWt = 0;
  if (fareUnit == "WGT") {
    chgWt = fareEngCd == "WFG" ? Math.ceil(fhhgwgt) : fhhgwgt;
  } else if (fareUnit == "R/T") {
    chgWt = v_wgt > v_msr ? wgt : msr;
  } else if (fareUnit == "CBM") {
    chgWt = msr;
  } else if (fareUnit == "M/T") {
    chgWt = fhhgwgt / 1000;
  } else if (fareUnit == "CASE") {
    chgWt = 1;
  } else {
    var cnt1type = ed_fhhcnt1type.getValue();
    var cnt2type = ed_fhhcnt2type.getValue();
    var cnt3type = ed_fhhcnt3type.getValue();
    var cnt4type = ed_fhhcnt4type.getValue();
    if (fareUnit == cnt1type) chgWt = Number(ed_fhhcnt1.getValue() || 0);else if (fareUnit == cnt2type) chgWt = Number(ed_fhhcnt2.getValue() || 0);else if (fareUnit == cnt3type) chgWt = Number(ed_fhhcnt3.getValue() || 0);else if (fareUnit == cnt4type) chgWt = Number(ed_fhhcnt4.getValue() || 0);else chgWt = 0;
  }
  ds_selling.setCellData(row, "chgWt", chgWt);
};

