scwin.f_PopUpGrid = function (disGubun, row, pWinCloseTF, pAllSearchTF) {
  if (ds_ocMblhList.getRowCount() < 1) {
    return;
  }
  var code = "";
  var name = "";
  switch (disGubun) {
    case "SellingCustomer":
      code = scwin.code || ds_selling.getCellData(row, "bilgClntNo");
      name = scwin.name || ds_selling.getCellData(row, "bilgClntNm");
      ds_selling.setCellData(row, "bilgClntNo", "");
      ds_selling.setCellData(row, "bilgClntNm", "");
      udc_mhlinercd.setSelectId('retrieveEngClntInfo');
      udc_mhlinercd.ilCommonPopUp(function (ret) {
        $c.gus.cfSetGridReturnValue($p, ret, ds_selling, row, "bilgClntNo", "bilgClntNm");
      }, code //코드
      , name //코드명
      , pWinCloseTF // 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '10' // 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
      , 'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN' // Title순서
      , '140,300,100,100,100,100,100,,,100' // 보여주는 각 컬럼들의 	폭
      , '8,9' // 컬럼중에서 숨기는	컬럼 지정
      , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때	원도우의	사용자 정의	폭
      , null // POP-UP뛰을때	우도우의	사용자 정의	높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , pAllSearchTF // 전체검색허용여부	("F")
      , 'Customer search,Customer Code,Customer Name' // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      , 'F' // Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
      );
      break;
    case "SellingFcode":
      code = scwin.code || ds_selling.getCellData(row, "fareEngCd");
      name = scwin.name || ds_selling.getCellData(row, "fareEngNm");
      ds_selling.setCellData(row, "fareEngCd", "");
      ds_selling.setCellData(row, "fareEngNm", "");
      udc_mhlinercd.setSelectId('retriveFreightCodeInfo');
      udc_mhlinercd.ilCommonPopUp(function (rtnList) {
        $c.gus.cfSetGridReturnValue($p, rtnList, ds_selling, row, "fareEngCd", "fareEngNm");
        if (undefined != rtnList) {
          ds_selling.setCellData(row, "sellItemCd", rtnList[3]);
          ds_selling.setCellData(row, "fareGrpCd", rtnList[5]);
          ds_selling.setCellData(row, "vatYn", rtnList[7]);
          if (rtnList[9] == "1") {
            //원화.
            ds_selling.setCellData(row, "crcCd", "KRW");
          } else {
            ds_selling.setCellData(row, "crcCd", lc_shhcucd.getValue());
          }
          if (ds_selling.getCellData(row, "fareEngCd") == "OCF") {
            ds_selling.getCellData(row, "crcCd", "USD");
          }
          if (ds_selling.getCellData(row, "fareEngCd") == "DOC" || ds_selling.getCellData(row, "fareEngCd") == "DOCV" || ds_selling.getCellData(row, "fareEngCd") == "DOF" || ds_selling.getCellData(row, "fareEngCd") == "DOFV" || ds_selling.getCellData(row, "fareEngCd") == "INSU" || ds_selling.getCellData(row, "fareEngCd") == "HDC" || ds_selling.getCellData(row, "fareEngCd") == "HDCV" || ds_selling.getCellData(row, "fareEngCd") == "CCFV" || ds_selling.getCellData(row, "fareEngCd") == "CCF") {
            ds_selling.setCellData(row, "fareUnit", "CASE");
            ds_selling.setCellData(row, "chgWt", "1");
          }
        }
      }, code //코드
      , name //코드명
      , pWinCloseTF // 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '2' // 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
      , "Code, Name" // Title순서
      , '80,230' // 보여주는	각 컬럼들의	폭
      , "3,4,5,6,7,8,9,10" // 컬럼중에서 숨기는	컬럼 지정
      , "S,1" // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때	원도우의	사용자 정의	폭
      , null // POP-UP뛰을때	우도우의	사용자 정의	높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , pAllSearchTF // 전체검색허용여부	("F")
      , "FCode,Code,Name" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      , 'F' // Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
      );
      break;
  }
};

//-------------------------------------------------------------------------
//Amount(외화) -- selling
//------------------------------------------------------------------------- 
scwin.f_sellingAmtFcrc = function (row, colid, olddata) {
  scwin.crc = ds_selling.getCellData(row, "crcCd");
  if (scwin.crc == "KRW") {
    ds_selling.setCellData(row, "sellAmtFcrc", 0);
  } else {
    var chgWt = Number(ds_selling.getCellData(row, "chgWt") || 0);
    var upr = Number(ds_selling.getCellData(row, "sellUpr") || 0);
    ds_selling.setCellData(row, "sellAmtFcrc", Math.round(chgWt * upr * 100) / 100);
  }
};
//-------------------------------------------------------------------------
//Amount(원화) -- selling Math.round(() * 100) / 100
//------------------------------------------------------------------------- 
scwin.f_sellingAmt = function (row, colid, olddata) {
  scwin.crc = ds_selling.getCellData(row, "crcCd");
  var amtF = Number(ds_selling.getCellData(row, "sellAmtFcrc") || 0);
  var exRate = Number(ds_selling.getCellData(row, "exRate") || 0);
  var amt = 0;
  if (scwin.crc == "KRW") {
    var chgWt = Number(ds_selling.getCellData(row, "chgWt") || 0);
    var upr = Number(ds_selling.getCellData(row, "sellUpr") || 0);
    amt = Math.round(chgWt * upr);
  } else if (scwin.crc == "JPY" || scwin.crc == "ITL" || scwin.crc == "IDR" || scwin.crc == "ESP") {
    amt = Math.round(amtF * exRate) / 100;
  } else {
    amt = Math.round(amtF * exRate);
  }
  ds_selling.setCellData(row, "sellAmt", amt);
};
//-------------------------------------------------------------------------
// Amount($) -- selling
//------------------------------------------------------------------------- 
scwin.f_sellingUsdAmt = function (row, colid, olddata) {
  if (ed_shhuexrate.getValue() != "0" && ed_shhuexrate.getValue() != "") {
    ds_selling.setCellData(row, "usdAmt", Math.round(ds_selling.getCellData(row, "sellAmt") / ed_shhuexrate.getValue() * 100) / 100);
  }
};
//-------------------------------------------------------------------------
// Vat -- selling
//------------------------------------------------------------------------- 
scwin.f_sellingVat = function (row, colid, olddata) {
  var vatYn = ds_selling.getCellData(row, "vatYn");
  if (vatYn == "0") {
    ds_selling.setCellData(row, "vatAmt", 0);
  } else {
    var sellAmt = Number(ds_selling.getCellData(row, "sellAmt") || 0);
    ds_selling.setCellData(row, "vatAmt", Math.round(sellAmt * 0.1 * 100) / 100);
  }
};

