//-------------------------------------------------------------------------
// Tab2, Selling 배포하기
//------------------------------------------------------------------------- 
scwin.f_distribute = async function () {
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getCellData(i, "chk") == "T" && ds_selling.getCellData(i, "distributeYn") == "Y") {
      await $c.win.alert($p, "이미 배포 되었습니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
      return false;
    }
  }
  ds_sellingDistribute.removeAll();
  ds_sellingDistributeTemp.removeAll();
  ds_sellingDistributeTemp.setJSON(ds_selling.getAllJSON(), false);
  for (var i = 0; i < ds_ocHblhList.getRowCount(); i++) {
    var blno = ds_ocHblhList.getCellData(i, "hhblno");
    var hhmsrrate = Number(ds_ocHblhList.getCellData(i, "hhmsrrate") || 0);
    var odrNo = ds_ocHblhList.getCellData(i, "odrNo");
    for (var j = 0; j < ds_sellingDistributeTemp.getRowCount(); j++) {
      ds_sellingDistributeTemp.setCellData(j, "blNo", blno);
      ds_sellingDistributeTemp.setCellData(j, "hhmsrrate", hhmsrrate);
      ds_sellingDistributeTemp.setCellData(j, "odrNo", odrNo);
      ds_sellingDistributeTemp.setCellData(j, "sellAmtFcrc", Number(ds_sellingDistributeTemp.getCellData(j, "sellAmtFcrc") || 0) * hhmsrrate / 100);
      ds_sellingDistributeTemp.setCellData(j, "sellAmt", Number(ds_sellingDistributeTemp.getCellData(j, "sellAmt") || 0) * hhmsrrate / 100);
      ds_sellingDistributeTemp.setCellData(j, "vatAmt", Number(ds_sellingDistributeTemp.getCellData(j, "vatAmt") || 0) * hhmsrrate / 100);
      ds_sellingDistributeTemp.setCellData(j, "usdAmt", Number(ds_sellingDistributeTemp.getCellData(j, "usdAmt") || 0) * hhmsrrate / 100);
    }
  }

  // distribute에 append(누적)
  ds_sellingDistribute.setJSON(ds_sellingDistributeTemp.getAllJSON(), false);
  ds_sellingDistributeTemp.removeAll();
  ds_sellingDistribute.modifyAllStatus("C");
  var rtn = await $c.sbm.execute($p, sbm_sellingDistribute);
  if (rtn.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
    await scwin.f_Retrieve();
  }
};

// Tab2, 배포취소
scwin.f_cancelDistribute = async function () {
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getCellData(i, "chk") == "T" && ds_selling.getCellData(i, "distributeYn") == "N") {
      await $c.win.alert($p, "배포내역이 없습니다.  \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
      return false;
    }
    if (ds_selling.getCellData(i, "chk") == "T") {
      ds_selling.modifyRowStatus(i, "D"); // 2 
    }
  }
  var rtn = await $c.sbm.execute($p, sbm_cancelSellingDistribute);
  if (rtn.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001);
    scwin.f_Retrieve();
  }
};

//-------------------------------------------------------------------------
//Selling sum
//------------------------------------------------------------------------- 
scwin.f_SellingSum = function () {
  var v_SellingSumAmount = 0,
    v_SellingSumAmountW = 0,
    v_SellingSumVat = 0,
    v_SellingSumAmountUs = 0;
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if (ds_selling.getRowStatus(i) !== 2) {
      v_SellingSumAmount += Number(ds_selling.getCellData(i, "sellAmtFcrc") || 0);
      v_SellingSumAmountW += Number(ds_selling.getCellData(i, "sellAmt") || 0);
      v_SellingSumVat += Number(ds_selling.getCellData(i, "vatAmt") || 0);
      v_SellingSumAmountUs += Number(ds_selling.getCellData(i, "usdAmt") || 0);
    }
  }
  ed_SellingSumAmount.setValue(v_SellingSumAmount);
  ed_SellingSumAmountW.setValue(v_SellingSumAmountW);
  ed_SellingSumVat.setValue(v_SellingSumVat);
  v_SellingAmountSum = v_SellingSumAmountW + v_SellingSumVat;
  ed_SellingAmountSum.setValue(v_SellingAmountSum);
};

//-------------------------------------------------------------------------
// 환율  Grid Selling 가져오기
//------------------------------------------------------------------------- 
scwin.f_ExRateSellingGridLoading = async function () {
  var row = ds_selling.getRowPosition() < 0 ? 0 : ds_selling.getRowPosition();
  var sellCrcCd = ds_selling.getCellData(row, "crcCd");
  var baseCrcCd = lc_shhcucd.getValue(); // (기존 BindColVal)
  var exGb = lc_shhexgb.getValue(); // (기존 BindColVal)
  var curDt = (ed_shhcurdt.getValue() || "").trim();

  // 동일통화면 화면 환율 사용
  if (baseCrcCd == sellCrcCd) {
    ds_selling.setCellData(row, "exRate", ed_shhexrate.getValue());
    return;
  }
  var exRate = ds_selling.getCellData(row, "exRate");
  if (!$c.util.isEmpty($p, exRate) && String(exRate) != "0") return;

  // 환율 조회  "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retrieveExRate"
  scwin._comboTarget = "EX_RATE_SELLING";
  await scwin.f_commCode("ilCommonEBC", "retrieveExRate", sellCrcCd, curDt, exGb);
  var rate = ds_exRateSellingGrid.getCellData(1, "CODE");
  ds_selling.setCellData(row, "exRate", rate);
  if ($c.util.isEmpty($p, rate) && sellCrcCd !== "KRW") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Ex-Rate"]);
  }
};

