scwin.f_tariffAllLoading = async function (disGubun) {
  // container type 계산
  var cnt1 = !$c.util.isEmpty($p, ed_fhhcnt1type.getValue()) && ed_fhhcnt1.getValue() != "0" ? ed_fhhcnt1type.getValue() : "0";
  var cnt2 = !$c.util.isEmpty($p, ed_fhhcnt2type.getValue()) && ed_fhhcnt2.getValue() != "0" ? ed_fhhcnt2type.getValue() : "0";
  var cnt3 = !$c.util.isEmpty($p, ed_fhhcnt3type.getValue()) && ed_fhhcnt3.getValue() != "0" ? ed_fhhcnt3type.getValue() : "0";
  var cnt4 = !$c.util.isEmpty($p, ed_fhhcnt4type.getValue()) && ed_fhhcnt4.getValue() != "0" ? ed_fhhcnt4type.getValue() : "0";
  ds_retrieveTariff.removeAll();
  ds_resultTariff.removeAll();
  var row = ds_retrieveTariff.insertRow(0);

  // Selling 존재 체크
  if (ds_selling.getRowCount() != 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["Selling Information"]);
    return;
  }
  if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) return; //저장하시겠습니까?	

  ds_retrieveTariff.setCellData(row, "fgubn", "1"); //selling , partner : 1, buying : 2
  ds_retrieveTariff.setCellData(row, "kcomcd", scwin.hd_kcomcd);
  ds_retrieveTariff.setCellData(row, "apdt", ed_mheta.getValue()); // ETA
  ds_retrieveTariff.setCellData(row, "customer", ed_shhcust.getValue());
  ds_retrieveTariff.setCellData(row, "partner", "");
  ds_retrieveTariff.setCellData(row, "liner", ed_mhlinercd.getValue());
  ds_retrieveTariff.setCellData(row, "loading", ed_mhlodcd.getValue());
  ds_retrieveTariff.setCellData(row, "discharge", ed_mhdisccd.getValue());
  ds_retrieveTariff.setCellData(row, "container1", cnt1);
  ds_retrieveTariff.setCellData(row, "container2", cnt2);
  ds_retrieveTariff.setCellData(row, "container3", cnt3);
  ds_retrieveTariff.setCellData(row, "container4", cnt4);
  ds_retrieveTariff.setCellData(row, "cbgubn", "C");
  ds_retrieveTariff.setCellData(row, "incoterm", "");
  ds_retrieveTariff.setCellData(row, "userid", scwin.userId || ""); // 필요시 서버 주입값 사용
  ds_retrieveTariff.setCellData(row, "flag", "1");
  ds_retrieveTariff.setCellData(row, "transTariffYn", "Y");
  ds_retrieveTariff.setCellData(row, "mhno", cnd_lc_mhno.getValue());

  // 조회
  await $c.sbm.execute($p, sbm_retrieveTariff);
  if (ds_resultTariff.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
    return;
  }

  // 결과 → Selling 생성
  for (var i = 0; i < ds_resultTariff.getRowCount(); i++) {
    scwin.f_FaddRow(1);
    ds_selling.setCellData(i, "fareEngCd", ds_resultTariff.getCellData(i, "fareEngCd"));
    scwin.f_PopUpGrid("SellingFcode", i, "T", "F"); // sellitemcd,faregrpcd,vatyn 세팅

    ds_selling.setCellData(i, "crcCd", ds_resultTariff.getCellData(i, "crcCd"));
    ds_selling.setCellData(i, "fareUnit", ds_resultTariff.getCellData(i, "fareUnit"));
    scwin.f_packageRateSellingLoading(i, ""); // chgWt 산정

    ds_selling.setCellData(i, "sellUpr", ds_resultTariff.getCellData(i, "amount"));
    scwin.f_sellingAmtFcrc(i, "", ""); // amount(외화)	
    scwin.f_ExRateSellingGridLoading(); // ex-rate
    scwin.f_sellingAmt(i, "", ""); // amount(원화)
    scwin.f_sellingVat(i, "", ""); // vat
    scwin.f_sellingUsdAmt(i, "", ""); // auount($)
  }

  // chgWt=0 삭제 (뒤에서 앞으로)
  for (var r = ds_selling.getRowCount(); r >= 1; r--) {
    if (String(ds_selling.getCellData(r, "chgWt")) == "0") {
      ds_selling.removeRow(r);
    }
  }
};

