// Customer Change 
//-------------------------------------------------------------------------
scwin.f_CustomerChange = async function (disGubun) {
  let opts = {
    id: "ilCommonCustomerChange",
    popupName: "Customer Change",
    modal: true,
    type: "browserPopup",
    width: 460,
    height: 280,
    title: "고객"
  };
  const rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonCustomerChange.xml", opts, {});
  if (!rtnList) return;
  if (rtnList[0] != "N/A") {
    return;
  }
  if (ds_selling.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]); //  @이(가) 존재하지 않습니다.
  } else {
    if (await $c.win.confirm($p, E_MSG_CM_CRM_001)) {
      //저장하시겠습니까?	
      for (var i = 0; i < ds_selling.getRowCount(); i++) {
        if ($c.util.isEmpty($p, ds_selling.getCellData(i, "certiNo"))) {
          if (ds_selling.getCellData(i, "bilgClntNo") == rtnList[1]) {
            ds_selling.setCellData(i, "bilgClntNo", rtnList[3]);
            ds_selling.setCellData(i, "bilgClntNm", rtnList[4]);
          }
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// Ex-rate Change 가져오기
//-------------------------------------------------------------------------
scwin.f_exRateChange = async function () {
  if (ds_selling.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Selling Information"]);
    return;
  }
  if (!(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
    //저장하시겠습니까?
    return;
  }
  for (var i = 0; i < ds_selling.getRowCount(); i++) {
    if ($c.util.isEmpty($p, ds_selling.getCellData(i, "certino"))) {
      if (ds_selling.getCellData(i, "crcCd") == lc_shhcucd.getValue().trim()) {
        ds_selling.setCellData(i, "exRate", ed_shhexrate.getValue()); //ex-rate 
        scwin.f_sellingAmt(i, "", ""); //amount(원화)	
        scwin.f_sellingVat(i, "", ""); //vat							
        scwin.f_sellingUsdAmt(i, "", ""); //auount($) 
      }
    }
  }
};

// 공통 코드조회 (param1~4)
// - sysCd 생략 시 "ilCommonEBC" 기본
scwin.f_commCode = async function (sysCd, queryId, param1, param2, param3, param4) {
  // sysCd 생략 호출 허용: f_commCode("queryId", p1, p2 ...)
  if (queryId == undefined) {
    queryId = sysCd;
    sysCd = "ilCommonEBC";
    param1 = param1;
    param2 = param2;
    param3 = param3;
    param4 = param4;
  }
  var params = {
    sysCd: sysCd || "ilCommonEBC",
    queryId: queryId || "",
    param1: param1 == undefined ? "" : param1,
    param2: param2 == undefined ? "" : param2,
    param3: param3 == undefined ? "" : param3,
    param4: param4 == undefined ? "" : param4
  };
  dma_combo.setEmptyValue();
  dma_combo.setJSON(params);
  var result = await $c.sbm.execute($p, sbm_combo);
  if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
    if (scwin._comboTarget == "SEA_CARGO") {
      ds_SeaCargoManifestCount.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "HMHNO") {
      ds_hmhno.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "HBL_CNTR") {
      ds_ocContList.setJSON(result.responseJSON.GAUCE);
      if (ds_ocContList.getRowCount() > 0) gr_ocContList.setFocusedCell(0, 0);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "MASTER_BL_NO") {
      // Master B/L No 
      ds_cndmhmblno.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "MASTER_HOUSE_BL_LIST") {
      ds_MasterHouseBlList.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "INVOICE_CHECK") {
      ds_invoiceCheck.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "DEPT_INFO") {
      ds_departmentInfo.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "EX_RATE") {
      ds_ExRate.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "UNIT_LIST") {
      ds_sellingUnit.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "CURRENCY_LOADING") {
      ds_currencyCode.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    } else if (scwin._comboTarget == "EX_RATE_SELLING") {
      ds_exRateSellingGrid.setJSON(result.responseJSON.GAUCE);
      scwin._comboTarget = "";
      return;
    }
  }
};

