// gr_selling OnClick(Row,Colid)
scwin.gr_selling_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (scwin.statusFlag == "U") {
    if (columnId == "fareEngNm") {
      gr_selling.setColumnReadOnly('fareEngNm', false); //, 'Edit') = "ANY"
    } else {
      gr_selling.setColumnReadOnly('fareEngNm', true); // Edit') = "none"
    }
  }
};

// for=gr_selling event=OnPopup(Row,Colid,data)
scwin.gr_selling_ontextimageclick = function (rowIndex, columnIndex) {
  var col = gr_selling.getColumnID(columnIndex);
  switch (col) {
    case "bilgClntNo":
      scwin.f_PopUpGrid("SellingCustomer", rowIndex, "F", "F", "F");
      break;
    case "fareEngCd":
      scwin.f_PopUpGrid("SellingFcode", rowIndex, "F", "F", "F");
      break;
  }
};

// gr_selling OnExit(Row,Colid,olddata)
scwin.gr_selling_onafteredit = async function (rowIndex, columnIndex, value) {
  const colID = gr_selling.getColumnID(columnIndex);
  const newValue = value || "";
  const olddata = ds_selling.getOriginalCellData(rowIndex, colID) || "";
  const row = rowIndex;
  switch (colID) {
    case "bilgClntNo":
      if (newValue != "") {
        scwin.code = ds_selling.getCellData(rowIndex, "bilgClntNo");
        scwin.name = ds_selling.getCellData(rowIndex, "bilgClntNm");
        scwin.f_PopUpGrid("SellingCustomer", row, "T", "F", "F");
      } else {
        scwin.code = "";
        scwin.name = "";
        ds_selling.setCellData(row, "bilgClntNm", "");
      }
      break;
    case "fareEngCd":
      //ds_selling.setCellData(row, "fareEngNm", "");
      if (newValue != "") {
        scwin.code = ds_selling.getCellData(rowIndex, "fareEngCd");
        scwin.name = ds_selling.getCellData(rowIndex, "fareEngNm");
        scwin.f_PopUpGrid("SellingFcode", row, "T", "F", "F");
      } else {
        scwin.code = "";
        scwin.name = "";
        ds_selling.setCellData(row, "fareEngNm", "");
      }
      scwin.f_sellingAmtFcrc(row, colID, olddata);
      scwin.f_sellingAmt(row, colID, olddata);
      scwin.f_sellingVat(row, colID, olddata);
      scwin.f_sellingUsdAmt(row, colID, olddata);
      break;
    case "crcCd":
      scwin.f_sellingAmtFcrc(row, colID, olddata);
      scwin.f_sellingAmt(row, colID, olddata);
      scwin.f_sellingVat(row, colID, olddata);
      scwin.f_sellingUsdAmt(row, colID, olddata);
      break;
    case "chgWt":
    case "sellUpr":
      scwin.f_sellingAmtFcrc(row, colID, olddata);
      scwin.f_sellingAmt(row, colID, olddata);
      scwin.f_sellingVat(row, colID, olddata);
      scwin.f_sellingUsdAmt(row, colID, olddata);
      break;
    case "exRate":
      scwin.f_sellingAmt(row, colID, olddata);
      break;
    case "sellAmt":
      scwin.f_sellingVat(row, colID, olddata);
      break;
    case "vatAmt":
      scwin.f_sellingUsdAmt(row, colID, olddata);
      break;
    case "fareUnit":
      // gr_selling event=OnCloseUp(Row,Colid), 콤보 창이 닫힐때 발생
      scwin.f_packageRateSellingLoading(row, colID);
      scwin.f_sellingTariffRateLoading();
      break;
    default:
      break;
  }
};

